			var VAR_PAGE_XPATH 		= "/ds/var/page";
			var DATA_XPATH 			= "/ds/ManageCase";
			function Header_PartyTypeListGrid() {};
			Header_PartyTypeListGrid.tabIndex 		= 2;
			//Header_PartyTypeListGrid.dataBinding 	= VAR_PAGE_XPATH + "/SelectedGridRow/SelectedParty";
			Header_PartyTypeListGrid.isReadOnly		= function() { return false; }
			Header_PartyTypeListGrid.srcData 		= DATA_XPATH + "/Parties";
			Header_PartyTypeListGrid.rowXPath 		= "LitigiousParty[./TypeCode = '" + PartyTypeCodesEnum.CLAIMANT + "' or ./TypeCode = '" + PartyTypeCodesEnum.DEFENDANT + "' or ./TypeCode = '" + PartyTypeCodesEnum.PART_20_DEFENDANT + "' or ./TypeCode = '" + PartyTypeCodesEnum.PART_20_CLAIMANT + "' or ./TypeCode = '" + PartyTypeCodesEnum.DEBTOR + "' or ./TypeCode = '" + PartyTypeCodesEnum.CREDITOR +"']";
			Header_PartyTypeListGrid.keyXPath 		= "PartyId";
			Header_PartyTypeListGrid.columns 		= [	{xpath: "Type"},
														{xpath: "Number", sort: "numerical", defaultSort:"true", defaultSortOrder:"ascending"},
														{xpath: "Name"}];		
														
			Header_PartyTypeListGrid.enableOn = [_caseNumberExistsXPath];
			Header_PartyTypeListGrid.isEnabled = function()
			{
				if(Services.getValue(_caseNumberExistsXPath) == "true") {
					return true;
				}
		        return false;
			}	
			
			Header_PartyTypeListGrid.mandatoryOn = [_caseNumberExistsXPath];
			Header_PartyTypeListGrid.isMandatory = function()
			{
				if(Services.getValue(_caseNumberExistsXPath) == "true") {
					return true;
				}
		        return false;
			}
			
			Header_PartyTypeListGrid.logicOn = [_caseNumberExistsXPath];
			Header_PartyTypeListGrid.logic = function(event)
			{
				if(event.getXPath() != _caseNumberExistsXPath ) {
					return;
				}
			
		        if ( Services.getValue(_caseNumberExistsXPath) != "true" )
				{
					Services.removeNode(this.srcData);
				}
			}
